import{_ as t,o as n,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"9. No Extra Claims","description":"","frontmatter":{"title":"9. No Extra Claims","eba":"Nurses and Midwives 2024-2028","topics":["union-matters","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/preliminary/9-no-extra-claims.md","filePath":"ebas/nurses-midwives/preliminary/9-no-extra-claims.md"}'),o={name:"ebas/nurses-midwives/preliminary/9-no-extra-claims.md"};function r(s,e,m,l,p,h){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_9-no-extra-claims" tabindex="-1">9. No Extra Claims <a class="header-anchor" href="#_9-no-extra-claims" aria-label="Permalink to &quot;9. No Extra Claims&quot;">​</a></h1><p><strong>9.1</strong> The Unions, the Employers and the Employees acknowledge and agree that:</p><p><strong>(a)</strong> this Agreement settles all claims in relation to the terms and conditions of employment of the Employees to whom it applies including all Union and</p><p>Part A - Preliminary</p><p>Employer claims made before and during the negotiations leading to the making of this Agreement (whether or not those claims were matters at issue during the bargaining period); and</p><p><strong>(b)</strong> except as otherwise indicated herein this Agreement sets out and is intended to set out comprehensively, all of the terms and conditions of employment of the Employees whose employment is subject to the Agreement; and</p><p><strong>(c)</strong> they will not pursue any extra claims during the term of this Agreement; and</p><p><strong>(d)</strong> nothing in this clause 9 limits the operation of <a href="/eba/ebas/nurses-midwives/safe-patient-care/105-interaction-with-the-safe-patient-care-act.html">clause 105</a> (Interaction with the Safe Patient Care Act) of this Agreement.</p><p><strong>9.2</strong> Subject to an Employer meeting its obligations to consult arising under this Agreement or a relevant contract of employment, it is not the intention of subclause 9.1(c) to inhibit, limit or restrict an Employer&#39;s right or ability to introduce change at the workplace.</p><p><strong>9.3</strong> Replacement Agreement</p><p>The Employers agree to commence discussions with the Unions no later than six months prior to the nominal expiry date of this Agreement. Provided that any claim made by a person covered by this Agreement during this period is not supported by industrial action, subclause 9.1(c) does not prevent a person covered by this Agreement from making a claim during the six month period (or such earlier period as may be agreed) prior to the nominal expiry date of this Agreement. Such discussions will be undertaken in good faith for the purpose of concluding a replacement agreement to this Agreement to operate from the nominal expiry date of this Agreement.</p>',11)])])}const g=t(o,[["render",r]]);export{d as __pageData,g as default};
